script:
frappe.ui.form.on('Procurement Consolidation', {
    refresh: function(frm) {
        // Jab table mein koi row select ho (Standard Checkbox)
        frm.fields_dict['items'].grid.wrapper.on('change', 'input[type="checkbox"]', function(e) {
            let $checkbox = $(e.currentTarget);
            let is_checked = $checkbox.is(':checked');
            
            // Agar ye "Select All" ya individual row selector hai
            let grid_row = $checkbox.closest('.grid-row').data('grid_row');
            
            if (grid_row) {
                let docname = grid_row.doc.name;
                // Aapke 'select_it' field ko update karega
                frappe.model.set_value('Consolidated Procurement Item', docname, 'select_item', is_checked ? 1 : 0);
            }
        });
    }
});

frappe.ui.form.on("Technical Survey", {
    refresh: function(frm) {
        // Set filters for component dropdowns
        set_component_filters(frm);

        // Auto-populate BOM if proposed_system is set and bom_reference is empty
        if (frm.doc.proposed_system && !frm.doc.bom_reference) {
            populate_bom_from_system(frm);
        }
    },

    proposed_system: function(frm) {
        if (frm.doc.proposed_system) {
            populate_bom_from_system(frm);
        } else {
            // Clear BOM fields if proposed_system is cleared
            clear_bom_fields(frm);
        }
    },

    populate_bom_btn: function(frm) {
        if (frm.doc.proposed_system) {
            populate_bom_from_system(frm);
        } else {
            frappe.msgprint(__("Please select a Proposed System first"));
        }
    }
});

function set_component_filters(frm) {
    // Filter for Panels
    frm.set_query("selected_panel", function() {
        return {
            filters: {
                "item_group": "Panels",
                "disabled": 0
            }
        };
    });

    // Filter for Inverters
    frm.set_query("selected_inverter", function() {
        return {
            filters: {
                "item_group": "Inverters",
                "disabled": 0
            }
        };
    });

    // Filter for Batteries
    frm.set_query("selected_battery", function() {
        return {
            filters: {
                "item_group": ["in", ["Batteries", "Battery", "Energy Storage"]],
                "disabled": 0
            }
        };
    });

    // Filter for Proposed System (Products only)
    frm.set_query("proposed_system", function() {
        return {
            filters: {
                "item_group": "Products",
                "is_sales_item": 1,
                "disabled": 0
            }
        };
    });
}

function populate_bom_from_system(frm) {
    frappe.call({
        method: "solar_erp.solar_erp.api.technical_survey.get_bom_payload",
        args: {
            proposed_system_item_code: frm.doc.proposed_system
        },
        freeze: true,
        freeze_message: __("Loading BOM..."),
        callback: function(r) {
            if (r.message) {
                let data = r.message;

                if (data.error) {
                    frappe.msgprint({
                        title: __("BOM Not Found"),
                        message: data.error,
                        indicator: "red"
                    });
                    return;
                }

                // Set BOM reference
                frm.set_value("bom_reference", data.bom);

                // Set default selections
                if (data.default_selected_panel) {
                    frm.set_value("selected_panel", data.default_selected_panel);
                }
                if (data.default_selected_inverter) {
                    frm.set_value("selected_inverter", data.default_selected_inverter);
                }
                if (data.default_selected_battery) {
                    frm.set_value("selected_battery", data.default_selected_battery);
                }

                // Set quantities
                let qty = data.qty_summary || {};
                frm.set_value("panel_qty_from_bom", qty.panel_qty_from_bom || 0);
                frm.set_value("inverter_qty_from_bom", qty.inverter_qty_from_bom || 0);
                frm.set_value("battery_qty_from_bom", qty.battery_qty_from_bom || 0);

                // Populate other items table
                frm.clear_table("bom_other_items");
                (data.other_items || []).forEach(function(item) {
                    let row = frm.add_child("bom_other_items");
                    row.item_code = item.item_code;
                    row.item_name = item.item_name;
                    row.qty = item.qty;
                    row.uom = item.uom;
                    row.description = item.description;
                });
                frm.refresh_field("bom_other_items");

                frappe.show_alert({
                    message: __("Bill of material has been populated based on your selection"),
                    indicator: "green"
                }, 5);
            }
        }
    });
}

function clear_bom_fields(frm) {
    frm.set_value("bom_reference", "");
    frm.set_value("selected_panel", "");
    frm.set_value("selected_inverter", "");
    frm.set_value("selected_battery", "");
    frm.set_value("panel_qty_from_bom", 0);
    frm.set_value("inverter_qty_from_bom", 0);
    frm.set_value("battery_qty_from_bom", 0);
    frm.clear_table("bom_other_items");
    frm.refresh_field("bom_other_items");
}

frappe.ui.form.on('Technical Survey', {
    refresh: function(frm) {
        frm.set_query('technical_executive', function() {
            return {
                filters: {
                    'enabled': 1
                },
                query: "frappe.core.doctype.user.user.user_query", // Standard user query
                filters: [
                    ['Has Role', 'role', '=', 'Vendor Executive']
                ]
            };
        });
    }
});

// Technical Survey - Assigned Vendor Permissions
// Make assigned_vendor read-only for Vendor Executive role

frappe.ui.form.on('Technical Survey', {
    refresh: function(frm) {
        // Check if user has Vendor Executive role (but not Manager roles)
        const has_vendor_exec_role = frappe.user_roles.includes('Vendor Executive') || 
                                      frappe.user_roles.includes('Technical Survey Executive');

        const has_manager_role = frappe.user_roles.includes('System Manager') || 
                                 frappe.user_roles.includes('Technical Survey Manager') ||
                                 frappe.user_roles.includes('Project Manager');

        // If user is Vendor Executive but not a Manager, make field read-only
        if (has_vendor_exec_role && !has_manager_role) {
            frm.set_df_property('assigned_vendor', 'read_only', 1);
            console.log('🔒 assigned_vendor is read-only for Vendor Executive');
        } else {
            console.log('✏️  assigned_vendor is editable for Manager/Admin');
        }
    }
});

frappe.ui.form.on('Project Installation', {
    refresh: function(frm) {
        // Agar status Draft hai, tabhi button dikhega
        if (frm.doc.workflow_state === 'Draft') {
            
            frm.add_custom_button(__('Initiate Project Installation'), function() {
                
                // 1. Validation Check (Jo aapne server script mein likha tha)
                if (!frm.doc.assigned_vendor) {
                    frappe.throw(__("Project Installation does not have any vendor assigned"));
                    return;
                }

                // 2. Confirmation Dialog
                frappe.confirm(`This will initiate the project for <b>${frm.doc.assigned_vendor}</b>. Continue?`, () => {
                    
                    // 3. Workflow Action Trigger
                    // Ye status ko 'Scheduled' ya 'In Progress' kar dega (as per your workflow)
                    frm.execute_action('Start'); 

                    frappe.show_alert({
                        message: __('Project Installation Initiated Successfully'),
                        indicator: 'green'
                    });
                });

            }, __("Actions"));
            
            // Button ko blue color dene ke liye
            frm.page.set_inner_button_group_class(__('Initiate Project Installation'), __("Actions"), 'btn-primary');
        }
    }
});

frappe.ui.form.on('Subsidy Application', {
  refresh(frm){
    frm.set_df_property('workflow_state','read_only',1);
    if (['Submitted','Under Review'].includes(frm.doc.workflow_state)){
      ['k_number','system_capacity_kw','electricity_bill_attachment'].forEach(f=>{
        if (frm.fields_dict[f]) frm.toggle_reqd(f,1);
        if (frm.fields_dict['custom_'+f]) frm.toggle_reqd('custom_'+f,1);
      });
    }
  }
});

frappe.ui.form.on('DISCOM Process', {
  refresh(frm){
    frm.set_df_property('workflow_state','read_only',1);
    ['discom','k_number','status'].forEach(f=>{
      if (frm.fields_dict[f]) frm.toggle_reqd(f,1);
      if (frm.fields_dict['custom_'+f]) frm.toggle_reqd('custom_'+f,1);
    });
  }
});
